<script lang="ts">
  import { onMount } from 'svelte';
  import {
    buildSyntheticDemoExport, createSyntheticDemoState, MAX_SYNTHETIC_DEMO_NOTE_LENGTH,
    normalizeSyntheticDemoState, SYNTHETIC_DEMO_CANDIDATES, SYNTHETIC_DEMO_PROFILE,
    SYNTHETIC_DEMO_STORAGE_KEY, SYNTHETIC_DEMO_VERSION, syntheticDemoCandidate,
    syntheticDemoStage,
  } from '$lib/analysis/demo-model.js';

  type View='brand'|'discover'|'triage'|'evidence'|'case';
  let demoState:ReturnType<typeof createSyntheticDemoState>=$state(createSyntheticDemoState());let view=$state<View>('brand');let message=$state('');
  const selected=$derived(syntheticDemoCandidate(demoState.selectedCandidateId));
  const views:Array<{id:View;label:string}>=[{id:'brand',label:'1. Brand'},{id:'discover',label:'2. Discover'},{id:'triage',label:'3. Triage'},{id:'evidence',label:'4. Evidence'},{id:'case',label:'5. Case'}];

  onMount(()=>{
    let stored:string|null;
    try{stored=sessionStorage.getItem(SYNTHETIC_DEMO_STORAGE_KEY);}catch{demoState=createSyntheticDemoState();message='Tab storage is unavailable. Demo progress will last only until this page closes.';return;}
    if(!stored)return;
    try{
      const parsed:unknown=JSON.parse(stored);
      if(!parsed||typeof parsed!=='object'||Array.isArray(parsed)||!('version' in parsed)||(parsed as {version?:unknown}).version!==SYNTHETIC_DEMO_VERSION)throw new Error('Unsupported demo state');
      demoState=normalizeSyntheticDemoState(parsed);view=syntheticDemoStage(demoState) as View;
    }catch{
      demoState=createSyntheticDemoState();view='brand';
      try{sessionStorage.removeItem(SYNTHETIC_DEMO_STORAGE_KEY);message='Stored demo progress was invalid or unsupported and has been reset.';}catch{message='Stored demo progress was invalid and could not be cleared. Closing this tab will remove it.';}
    }
  });
  function available(target:View){return target==='brand'||(target==='discover'&&demoState.profileReady)||(target==='triage'&&demoState.candidatesReady)||(target==='evidence'&&Boolean(demoState.selectedCandidateId))||(target==='case'&&demoState.caseReady);}
  function save(patch:Record<string,unknown>,successMessage?:string){demoState=normalizeSyntheticDemoState({...demoState,...patch});try{sessionStorage.setItem(SYNTHETIC_DEMO_STORAGE_KEY,JSON.stringify(demoState));if(successMessage!==undefined)message=successMessage;}catch{message='Progress updated in memory, but tab storage is unavailable. Reloading will reset the demo.';}}
  function loadProfile(){save({profileReady:true},'Synthetic profile loaded. No production profile was created.');view='discover';}
  function generate(){save({candidatesReady:true},'Loaded three fixed synthetic candidates without making a request.');view='triage';}
  function inspect(id:string){save({selectedCandidateId:id,caseReady:false,caseStatus:'new',note:''},'Opened bounded fixture evidence.');view='evidence';}
  function openCase(){save({caseReady:true},'Created an isolated synthetic case in this tab only.');view='case';}
  function updateCase(patch:Record<string,unknown>,announce=true){save(patch,announce?'Synthetic case updated.':undefined);}
  function reset(){demoState=createSyntheticDemoState();view='brand';try{sessionStorage.removeItem(SYNTHETIC_DEMO_STORAGE_KEY);message='Synthetic demo reset.';}catch{message='Demo reset in memory, but tab storage could not be cleared. Closing this tab will remove its demo state.';}}
  function exportCase(){const payload=buildSyntheticDemoExport(demoState,new Date().toISOString());const url=URL.createObjectURL(new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}));const anchor=document.createElement('a');anchor.href=url;anchor.download='whoisleuth-synthetic-demo-case.json';anchor.click();URL.revokeObjectURL(url);message='Synthetic case export created. It is clearly marked as demonstration data.';}
</script>

<svelte:head><title>Synthetic demo · WHOISleuth</title><meta name="description" content="Explore a bounded synthetic WHOISleuth investigation without live lookups."></svelte:head>
<header class="demo-header"><a class="demo-brand" href="/demo"><img src="/favicon.svg" alt=""><strong>WHOISleuth</strong></a><nav aria-label="Demo links"><a href="/" data-sveltekit-reload>Sign in</a><a href="/privacy">Privacy</a></nav></header>
<section class="demo-hero"><p class="eyebrow">Public synthetic demo</p><h1>Follow a finding from discovery to case export.</h1><p>Explore a fixed, fictional investigation using reserved domains. No live registry, DNS, website, certificate, or hosted API request is made.</p><div class="synthetic-flag">Synthetic fixtures · No live findings</div></section>

<nav class="demo-steps card" aria-label="Synthetic investigation stages">{#each views as item}<button type="button" disabled={!available(item.id)} aria-current={view===item.id?'step':undefined} class:active={view===item.id} onclick={()=>view=item.id}>{item.label}</button>{/each}</nav>
<div class="demo-actions"><button type="button" onclick={reset}>Reset demo</button><span role="status" aria-live="polite">{message}</span></div>

{#if view==='brand'}
  <section class="demo-panel card" aria-labelledby="brand-heading"><p class="eyebrow">Step 1</p><h2 id="brand-heading">Define the protected brand</h2><p>The real Brands workspace stores profiles locally. This demo uses one immutable fixture.</p><dl><div><dt>Brand</dt><dd>{SYNTHETIC_DEMO_PROFILE.name}</dd></div><div><dt>Official domain</dt><dd><code>{SYNTHETIC_DEMO_PROFILE.officialDomain}</code></dd></div><div><dt>Products</dt><dd>{SYNTHETIC_DEMO_PROFILE.products.join(', ')}</dd></div><div><dt>Coverage</dt><dd>{SYNTHETIC_DEMO_PROFILE.monitoredTlds.join(', ')}</dd></div></dl><button class="primary" type="button" onclick={loadProfile}>Use synthetic profile</button></section>
{:else if view==='discover'}
  <section class="demo-panel card" aria-labelledby="discover-heading"><p class="eyebrow">Step 2</p><h2 id="discover-heading">Generate candidate coverage</h2><p>Live Discover can generate bounded variations and search Certificate Transparency. Here, the next action only reveals three fixed local records.</p><div class="preview-list"><span>Character edit</span><span>Impersonation term</span><span>Alternate TLD</span></div><button class="primary" type="button" onclick={generate}>Load synthetic candidates</button></section>
{:else if view==='triage'}
  <section class="demo-panel" aria-labelledby="triage-heading"><p class="eyebrow">Step 3</p><h2 id="triage-heading">Triage candidates</h2><p>Scores and signals below are fixtures for demonstrating prioritisation, not claims about real domains.</p><div class="candidate-grid">{#each SYNTHETIC_DEMO_CANDIDATES as candidate}<article class="candidate card"><div><code>{candidate.domain}</code><span class:high={candidate.risk>=70}>Risk {candidate.risk}</span></div><p>{candidate.mutation} · {candidate.availability}</p><ul>{#each candidate.signals as signal}<li>{signal}</li>{/each}</ul><button type="button" onclick={()=>inspect(candidate.id)}>Inspect {candidate.domain}</button></article>{/each}</div></section>
{:else if view==='evidence'&&selected}
  <section class="demo-panel card" aria-labelledby="evidence-heading"><p class="eyebrow">Step 4 · Synthetic evidence</p><h2 id="evidence-heading">{selected.domain}</h2><p>WHOISleuth separates direct observations, derived context, and limitations. Every value here is a local fixture.</p><dl><div><dt>Registrar</dt><dd>{selected.evidence.registrar}</dd></div><div><dt>Registration</dt><dd>{selected.evidence.registeredAt}</dd></div><div><dt>Nameservers</dt><dd>{selected.evidence.nameservers.join(', ')||'Not observed'}</dd></div><div><dt>Website</dt><dd>{selected.evidence.website}</dd></div><div><dt>Certificate</dt><dd>{selected.evidence.certificate}</dd></div><div><dt>Mail</dt><dd>{selected.evidence.mail}</dd></div></dl><div class="limitation"><strong>Interpretation limit</strong><p>These signals demonstrate workflow and explainability only. Similar observations in a live lookup would require analyst review.</p></div><button class="primary" type="button" onclick={openCase}>Open synthetic case</button></section>
{:else if view==='case'&&selected}
  <section class="demo-panel card" aria-labelledby="case-heading"><p class="eyebrow">Step 5 · Isolated case</p><h2 id="case-heading">Document {selected.domain}</h2><p>This case is stored only under the demo's tab-scoped key and never appears in Monitor.</p><label>Status<select value={demoState.caseStatus} onchange={(event)=>updateCase({caseStatus:(event.currentTarget as HTMLSelectElement).value})}><option value="new">New</option><option value="reviewing">Reviewing</option><option value="monitoring">Monitoring</option></select></label><label>Analyst note<textarea maxlength={MAX_SYNTHETIC_DEMO_NOTE_LENGTH} value={demoState.note} oninput={(event)=>updateCase({note:(event.currentTarget as HTMLTextAreaElement).value},false)} placeholder="Optional synthetic note"></textarea></label><div class="case-actions"><button class="primary" type="button" onclick={exportCase}>Export synthetic JSON</button><button type="button" onclick={()=>view='evidence'}>Review evidence</button></div><p class="export-warning">Exports are marked <code>synthetic: true</code> and must not be used as evidence or an abuse report.</p></section>
{/if}

<footer class="demo-footer"><p>Ready for live investigation? <a href="/" data-sveltekit-reload>Sign in to the protected console</a>.</p><p>© 2026 WHOISleuth · <a href="/privacy">Privacy</a></p></footer>

<style>
  .demo-header{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-bottom:52px}.demo-brand{display:flex;align-items:center;gap:10px;font-family:var(--mono)}.demo-brand img{width:36px;height:36px}.demo-header nav{display:flex;gap:8px;margin:0}.demo-header nav a,.demo-actions button,.candidate button,.case-actions button{padding:9px 12px;border:1px solid var(--border);border-radius:8px;background:var(--panel);font:700 .7rem var(--mono)}.demo-hero{max-width:850px}.demo-hero h1{margin:.25rem 0;font:700 clamp(2rem,5vw,3.7rem) var(--mono);letter-spacing:-.055em}.demo-hero>p:not(.eyebrow){max-width:70ch;color:var(--muted);line-height:1.6}.synthetic-flag{display:inline-block;margin-top:9px;padding:7px 10px;border:1px solid var(--amber);border-radius:999px;color:var(--amber);font:700 .66rem var(--mono)}.demo-steps{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:1px;margin:30px 0 12px;padding:5px}.demo-steps button{min-height:42px;border:0;border-radius:7px;background:transparent;color:var(--muted);font-size:.66rem}.demo-steps button.active{background:rgba(126,224,168,.1);color:var(--accent2)}.demo-actions{display:flex;min-height:40px;align-items:center;gap:14px;margin-bottom:18px}.demo-actions span{color:var(--muted);font-size:.68rem}.demo-panel{padding:clamp(22px,4vw,38px)}.demo-panel>h2{margin:.25rem 0 8px;font:700 clamp(1.4rem,3vw,2rem) var(--mono)}.demo-panel>p:not(.eyebrow),.candidate p,.export-warning{color:var(--muted);line-height:1.55}.demo-panel dl{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:1px;margin:24px 0}.demo-panel dl div{min-width:0;padding:14px;border:1px solid var(--border)}dt{color:var(--muted);font-size:.63rem;text-transform:uppercase}dd{margin:6px 0 0;overflow-wrap:anywhere}code{color:var(--accent);font-family:var(--mono)}.preview-list{display:flex;flex-wrap:wrap;gap:8px;margin:24px 0}.preview-list span{padding:8px 10px;border:1px solid var(--border);border-radius:7px;color:var(--muted);font-size:.7rem}.candidate-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.candidate{display:flex;min-width:0;flex-direction:column;padding:18px}.candidate>div{display:flex;align-items:flex-start;flex-direction:column;gap:8px}.candidate code{overflow-wrap:anywhere;font-size:.86rem}.candidate span{color:var(--amber);font:700 .65rem var(--mono)}.candidate span.high{color:var(--danger)}.candidate ul{padding-left:19px;color:var(--muted);font-size:.7rem;line-height:1.5}.candidate button{width:100%;margin-top:auto;color:var(--text)}.limitation{margin:20px 0;padding:14px;border-left:3px solid var(--amber);background:rgba(242,184,75,.04)}.limitation p{margin:5px 0 0;color:var(--muted)}.demo-panel label{display:block;margin:18px 0;color:var(--muted);font-size:.7rem}.demo-panel select,.demo-panel textarea{display:block;margin-top:7px;padding:10px}.demo-panel textarea{min-height:120px;resize:vertical}.case-actions{display:flex;flex-wrap:wrap;gap:8px}.case-actions .primary{color:#07101c;background:linear-gradient(135deg,#75c2ff,#4a9ff3)}.demo-footer{display:flex;justify-content:space-between;gap:20px;margin-top:45px;padding-top:18px;border-top:1px solid var(--border);color:var(--muted);font-size:.68rem}.demo-footer a{color:var(--accent)}
  @media(max-width:760px){.demo-header{margin-bottom:34px}.demo-steps{grid-template-columns:1fr}.demo-steps button{text-align:left}.demo-actions,.demo-footer{align-items:flex-start;flex-direction:column}.candidate-grid,.demo-panel dl{grid-template-columns:1fr}}
</style>
